parameters.jsCode:
const sessionId = $('Leer Contexto').first().json.sessionId;
const esDespedida = $('Leer Contexto').first().json.esDespedida;
const stored = $getWorkflowStaticData('global');
const ctxKey = 'ctx_' + sessionId;
const chatInput = $('Leer Contexto').first().json.chatInput || '';
const output = $input.first().json.output || $input.first().json.text || $input.first().json.response || $input.first().json.message || '';

if (esDespedida) {
  delete stored[ctxKey];
} else {
  const ctx = stored[ctxKey] || {};
  const nombreMatch = chatInput.match(/(?:me llamo|soy|mi nombre es)\s+([A-Za-z\u00e0-\u00fc]+)/i);
  if (nombreMatch && !ctx.nombre) ctx.nombre = nombreMatch[1];
  const docsMatch = chatInput.match(/(\d+)\s*(?:facturas?|documentos?|tiquetes?)/i);
  if (docsMatch && !ctx.documentos) ctx.documentos = docsMatch[1];
  stored[ctxKey] = ctx;
}

return [{ json: { output } }];

