const sessionId = $input.first().json.sessionId;
const chatInput = $input.first().json.mensaje || '';
const stored = $getWorkflowStaticData('global');
const ctxKey = 'ctx_' + sessionId;
const ctx = stored[ctxKey] || {
  nombre: null,
  negocio: null,
  documentos: null,
  fase: 1
};

const esDespedida = [
  /\b(adios|adiós|hasta luego|chao|bye|hasta pronto|nos vemos)\b/i,
  /gracias.{0,10}(hasta|bye|adios|chao|luego)/i,
  /que\s*tenga[sn]?\s*(buen|un\s*buen)/i,
  /ya\s*(es|fue)\s*todo/i,
  /eso\s*es\s*todo/i,
  /ya\s*(me\s*)?(resolvieron|quedo|lo\s*resolviste)/i,
  /problema\s*(resuelto|solucionado)/i,
  /^(ok|okay|perfecto|excelente|listo|claro|entendido)\s*[,.]?\s*(gracias|bye|chao|adios)?\s*\.?$/i
].some(p => p.test(chatInput.trim()));

if (esDespedida) {
  delete stored[ctxKey];
}

const nombreMatch = chatInput.match(/(?:me llamo|soy|mi nombre es)\s+([A-Za-zÀ-ú]+)/i);
if (nombreMatch && !ctx.nombre) ctx.nombre = nombreMatch[1];

const docsMatch = chatInput.match(/(\d+)\s*(?:facturas?|documentos?|tiquetes?)/i);
if (docsMatch && !ctx.documentos) ctx.documentos = docsMatch[1];

if (!esDespedida) stored[ctxKey] = ctx;

return [{ json: { chatInput, sessionId, ctx, esDespedida } }];

